// Prepare Data - Pega dados da planilha incluindo Raw_Content_Body
const input = $input.all()[0].json;

// Função para buscar campo com variações
function getField(obj, ...keys) {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') {
      return obj[key];
    }
  }
  return null;
}

// Gerar slug a partir do título
function generateSlug(title) {
  if (!title) return 'untitled-' + Date.now();
  return title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .substring(0, 60);
}

const title = getField(input, 'Title', 'title', 'TITLE') || 'Untitled Article';
let slug = getField(input, 'Slug', 'slug', 'SLUG');
if (!slug) slug = generateSlug(title);

// RAW CONTENT BODY - O HTML do artigo da planilha
const rawContentBody = getField(input, 'Raw_Content_Body', 'raw_content_body', 'RawContentBody', 'content', 'Content') || '';

// Read Time da planilha ou calcular
let readTime = parseInt(getField(input, 'Read_Time', 'read_time', 'ReadTime')) || 0;
if (!readTime && rawContentBody) {
  const wordCount = rawContentBody.replace(/<[^>]*>/g, ' ').split(/\s+/).filter(w => w.length > 0).length;
  readTime = Math.max(1, Math.ceil(wordCount / 200));
}
if (!readTime) readTime = 8;

// Word Count
let wordCount = parseInt(getField(input, 'Word_Count', 'word_count', 'WordCount')) || 0;
if (!wordCount && rawContentBody) {
  wordCount = rawContentBody.replace(/<[^>]*>/g, ' ').split(/\s+/).filter(w => w.length > 0).length;
}
if (!wordCount) wordCount = 1200;

return [{
  json: {
    title: title,
    slug: slug,
    category: getField(input, 'Category', 'category', 'CATEGORY') || 'General',
    primaryKeyword: getField(input, 'Primary_Keyword', 'primary_keyword', 'Primary Keyword') || '',
    secondaryKeywords: getField(input, 'Secondary_Keywords', 'secondary_keywords', 'Secondary Keywords') || '',
    targetCity: getField(input, 'Target_City', 'target_city', 'Target City') || 'Atlanta',
    wordCount: wordCount,
    readTime: readTime,
    rawContentBody: rawContentBody,
    publishDate: new Date().toISOString().split('T')[0],
    blogUrl: 'https://santoscsolutions.com/blog/' + slug + '/'
  }
}];

const response = $input.first().json;
const content = response.output || '{}';

try {
  let research = content;
  if (typeof content === 'string') {
    research = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    research = JSON.parse(research);
  }

  const articleData = $('📋 Prepare Data').first().json;

  return [{
    json: {
      ...articleData,
      research: {
        faq_questions: research.faq_questions || [],
        unique_angles: research.unique_angles || [],
        atlanta_data: research.atlanta_data || [],
        competitor_gaps: research.competitor_gaps || [],
        pricing_data: research.pricing_data || {}
      }
    }
  }];
} catch (e) {
  const articleData = $('📋 Prepare Data').first().json;
  return [{
    json: {
      ...articleData,
      research: {
        faq_questions: ['What does professional cleaning cost?', 'How often should I clean?'],
        unique_angles: ['Local Atlanta perspective', 'Real pricing transparency'],
        atlanta_data: ['Atlanta metro has 6M+ residents', 'High demand in Buckhead, Alpharetta'],
        competitor_gaps: ['Most articles are generic', 'No real pricing'],
        pricing_data: { standard: '$120-220', deep: '$200-400', moveout: '$299+' }
      }
    }
  }];
}

const response = $input.first().json;
const content = response.output || '{}';
const prevData = $('🔄 Parse Research').first().json;

try {
  let outline = content;
  if (typeof content === 'string') {
    outline = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    outline = JSON.parse(outline);
  }
  return [{json: {...prevData, outline: outline}}];
} catch (e) {
  return [{json: {...prevData, outline: {hook: 'Looking for professional cleaning in Atlanta?', structure: [{h2: 'Why Professional Cleaning Matters'}, {h2: 'Pricing Guide'}, {h2: 'FAQ'}]}}}];
}

const response = $input.first().json;
let articleContent = response.output || '';
const prevData = $('🔄 Parse Outline').first().json;

articleContent = articleContent.replace(/```html\n?/g, '').replace(/```\n?/g, '').trim();
const wordCount = articleContent.replace(/<[^>]*>/g, ' ').split(/\s+/).filter(w => w.length > 0).length;

return [{json: {...prevData, articleContent: articleContent, wordCount: wordCount}}];

const response = $input.first().json;
const content = response.output || '{}';

// Buscar dados anteriores de forma segura
let prevData = {};
try {
  prevData = $('🔄 Parse Article').first().json || {};
} catch (e) {
  prevData = $input.first().json || {};
}

// Garantir que title existe
const title = prevData.title || 'Santos Cleaning Article';

try {
  let seo = content;
  if (typeof content === 'string') {
    seo = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    seo = JSON.parse(seo);
  }
  return [{json: {...prevData, seo: seo}}];
} catch (e) {
  // Default SEO com tratamento de null
  return [{
    json: {
      ...prevData,
      seo: {
        title_tag: (title || 'Article').substring(0, 55) + ' | Santos Cleaning',
        meta_description: 'Professional cleaning in Atlanta. Get your free quote today! (866) 350-9407',
        og_description: 'Premium cleaning services in Atlanta by Santos Cleaning Solutions.',
        schema_faq: []
      }
    }
  }];
}

const response = $input.first().json;
const content = response.output || '{}';
const prevData = $('🔄 Parse SEO').first().json;

try {
  let review = content;
  if (typeof content === 'string') {
    review = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    review = JSON.parse(review);
  }
  return [{json: {...prevData, quality: {scores: review.scores || {}, totalScore: review.total_score || 0, passed: review.passed || false, issues: review.issues || []}}}];
} catch (e) {
  const passed = prevData.wordCount >= 1500;
  return [{json: {...prevData, quality: {totalScore: passed ? 85 : 60, passed: passed, issues: []}}}];
}

// 💉 Inject Article Card - VERSÃO CORRIGIDA COM MERGE
// Recebe dados combinados do Build HTML + Get Blog Index

const mergedData = $input.all()[0].json;

// ✅ Função para converter URL do Google Drive para formato lh3
function convertToLh3(url) {
  if (!url) return null;

  // Já está no formato correto
  if (url.includes('lh3.googleusercontent.com')) {
    return url;
  }

  // Converter de drive.google.com/uc?export=view&id=XXX
  const ucMatch = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  if (ucMatch) {
    return `https://lh3.googleusercontent.com/d/${ucMatch[1]}`;
  }

  // Converter de drive.google.com/file/d/XXX/view
  const fileMatch = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (fileMatch) {
    return `https://lh3.googleusercontent.com/d/${fileMatch[1]}`;
  }

  return url;
}

// ✅ Dados do artigo (agora vêm do Merge!)
const title = mergedData.title || 'New Article';
const slug = mergedData.slug || 'new-article';
const targetCity = mergedData.targetCity || 'Atlanta';
const category = mergedData.category || 'Cleaning';
const readTime = mergedData.readTime || 8;
const publishDate = mergedData.publishDate || new Date().toISOString().split('T')[0];

// ✅ Imagem convertida para formato lh3
const heroImage = convertToLh3(mergedData.heroImage) || 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1600&h=800&fit=crop&q=80';

// Formatar data para exibição
const dateObj = new Date(publishDate);
const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
const dateFormatted = `${monthNames[dateObj.getMonth()]} ${dateObj.getDate()}, ${dateObj.getFullYear()}`;

// Descrição curta para o card
const shortDescription = mergedData.metaDescription 
  ? mergedData.metaDescription.substring(0, 100) + '...'
  : `${title.substring(0, 80)}...`;

// ✅ Dados do blog index (content e sha)
const blogContent = mergedData.content || '';
const sha = mergedData.sha || '';

// Decodificar o conteúdo base64
const currentHtml = Buffer.from(blogContent, 'base64').toString('utf8');

// ✅ Template HTML do card
const cardHtml = `
    <article class="blog-card">
      <a href="/blog/${slug}/" class="blog-card-link" style="text-decoration: none; color: inherit;">
        <div class="blog-card-image" style="background-image: url('${heroImage}'); background-size: cover; background-position: center; height: 200px; position: relative; border-radius: 8px 8px 0 0;">
          <span class="blog-category" style="position: absolute; top: 12px; left: 12px; background: #2088D3; color: white; padding: 6px 14px; border-radius: 4px; font-size: 0.8rem; font-weight: 500;">${category}</span>
        </div>
        <div class="blog-card-content" style="padding: 20px;">
          <div class="blog-meta" style="display: flex; gap: 15px; font-size: 0.85rem; color: #666; margin-bottom: 12px; flex-wrap: wrap;">
            <span><i class="fas fa-calendar"></i> ${dateFormatted}</span>
            <span><i class="fas fa-map-marker-alt"></i> ${targetCity}, GA</span>
            <span><i class="fas fa-clock"></i> ${readTime} min read</span>
          </div>
          <h3 style="margin-bottom: 10px; color: #1a1a2e; font-size: 1.2rem; line-height: 1.4;">${title}</h3>
          <p style="color: #666; font-size: 0.95rem; line-height: 1.6; margin-bottom: 15px;">${shortDescription}</p>
          <span class="read-more" style="color: #2088D3; font-weight: 600; display: inline-block;">Read More →</span>
        </div>
      </a>
    </article>`;

// Encontrar onde inserir o novo card
let updatedHtml = currentHtml;
let inserted = false;

// Padrões de onde inserir
const patterns = [
  /(<div class="blog-grid"[^>]*>)/i,
  /(<div class="articles-grid"[^>]*>)/i,
  /(<section class="blog-posts"[^>]*>)/i
];

for (const pattern of patterns) {
  if (pattern.test(updatedHtml)) {
    updatedHtml = updatedHtml.replace(pattern, (match) => {
      inserted = true;
      return match + '\n' + cardHtml;
    });
    if (inserted) break;
  }
}

// Se não encontrou, inserir antes do </main>
if (!inserted && updatedHtml.includes('</main>')) {
  updatedHtml = updatedHtml.replace('</main>', cardHtml + '\n</main>');
  inserted = true;
}

// Codificar de volta para base64
const updatedContent = Buffer.from(updatedHtml).toString('base64');

return [{
  json: {
    content: updatedContent,
    sha: sha,
    path: 'frontend-production/blog/index.html',
    title: title,
    slug: slug,
    targetCity: targetCity,
    heroImage: heroImage,
    inserted: inserted
  }
}];

// Gerar prompt para Kie AI baseado no artigo
const data = $input.all()[0].json;

const prompt = `Professional cleaning service hero image for blog article. 
Title: "${data.title}"
Location: ${data.targetCity || 'Atlanta'}, Georgia
Style: Modern clean home interior, bright natural lighting, 
professional cleaning team at work, spotless surfaces, 
welcoming atmosphere, photorealistic, high quality, 16:9 aspect ratio`;

return [{
  json: {
    prompt: prompt,
    title: data.title,
    slug: data.slug
  }
}];

// Extrair URL da imagem gerada pelo Kie AI
const inputItem = $input.all()[0].json;

let tempImageUrl = null;

// Tentar extrair URL do resultado do Kie AI
if (inputItem?.data?.resultJson) {
  const resultJson = typeof inputItem.data.resultJson === 'string'
    ? JSON.parse(inputItem.data.resultJson)
    : inputItem.data.resultJson;

  if (resultJson.resultUrls?.length > 0) {
    tempImageUrl = resultJson.resultUrls[0];
  }
}

// Dados do Prepare Data
const prepareData = $('📋 Prepare Data').all()[0].json;

// ✅ FALLBACK: Se Kie AI falhar, usar Unsplash
const fallbackUrl = 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1600&h=800&fit=crop&q=80';

return [{
  json: {
    ...prepareData,
    tempImageUrl: tempImageUrl || fallbackUrl,
    hasImage: !!tempImageUrl,
    useFallback: !tempImageUrl
  }
}];

// Extrair URL pública do Google Drive
const uploadResult = $('📤 Upload to Google Drive').all()[0].json;
const prepareData = $('📋 Prepare Data').all()[0].json;

const fileId = uploadResult.id;

// ✅ FORMATO CORRETO: lh3.googleusercontent.com (funciona sempre!)
const publicUrl = fileId ? `https://lh3.googleusercontent.com/d/${fileId}` : null;

// Fallback para Unsplash se upload falhou
const heroImage = publicUrl || 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1600&h=800&fit=crop&q=80';

return [{
  json: {
    ...prepareData,
    heroImage: heroImage,
    driveFileId: fileId
  }
}];

// Build Final HTML - VERSÃO COMPLETA COM CONVERSÃO DE IMAGEM CORRETA
const inputData = $input.all()[0].json;
const prepareData = $('📋 Prepare Data').all()[0].json;

// ✅ FUNÇÃO PARA CONVERTER URL DO GOOGLE DRIVE PARA FORMATO LH3
function convertToLh3(url) {
  if (!url) return null;

  // Já está no formato correto lh3
  if (url.includes('lh3.googleusercontent.com')) {
    return url;
  }

  // Converter de drive.google.com/uc?export=view&id=XXX para lh3
  const ucMatch = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  if (ucMatch) {
    return `https://lh3.googleusercontent.com/d/${ucMatch[1]}`;
  }

  // Converter de drive.google.com/file/d/XXX/view para lh3
  const fileMatch = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (fileMatch) {
    return `https://lh3.googleusercontent.com/d/${fileMatch[1]}`;
  }

  // Retornar URL original se não for do Google Drive
  return url;
}

// Hero image do Google Drive - CONVERTIDO PARA LH3
const rawHeroImage = inputData.heroImage || prepareData.heroImage || null;
const heroImage = convertToLh3(rawHeroImage) || 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1600&h=800&fit=crop&q=80';

// CONTEÚDO DO ARTIGO
let articleContent = prepareData.rawContentBody || '';

// Tentar buscar dos agentes se planilha vazia
if (!articleContent || articleContent.trim() === '') {
  try {
    const qualityData = $('🔄 Parse Quality').all()[0].json;
    const articleData = $('🔄 Parse Article').all()[0].json;
    articleContent = qualityData?.quality?.improved_article 
      || qualityData?.articleContent 
      || articleData?.articleContent 
      || '<p>Professional cleaning services.</p>';
  } catch (e) {
    articleContent = '<p>Professional cleaning services.</p>';
  }
}

// REMOVER H2 "Call to Action" do conteúdo
articleContent = articleContent.replace(/<h2[^>]*>\s*Call to Action\s*<\/h2>/gi, '');
articleContent = articleContent.replace(/<h2>\s*Call to Action\s*<\/h2>/gi, '');

// Dados básicos
const title = prepareData.title || 'Professional Cleaning Services';
const slug = prepareData.slug || 'cleaning-services';
const category = prepareData.category || 'Cleaning';
const targetCity = prepareData.targetCity || 'Atlanta';
const primaryKeyword = prepareData.primaryKeyword || 'cleaning services';
const secondaryKeywords = prepareData.secondaryKeywords || '';

// KEYWORDS COMPLETAS (primary + secondary)
const allKeywords = [primaryKeyword, ...secondaryKeywords.split(',').map(k => k.trim()).filter(k => k)].join(', ');

// Read Time e Word Count
let readTime = parseInt(prepareData.readTime) || 0;
let wordCount = parseInt(prepareData.wordCount) || 0;
if (!readTime && articleContent) {
  const textOnly = articleContent.replace(/<[^>]*>/g, ' ');
  wordCount = textOnly.split(/\s+/).filter(w => w.length > 0).length || 1200;
  readTime = Math.max(1, Math.ceil(wordCount / 200));
}
if (!readTime) readTime = 8;
if (!wordCount) wordCount = 1200;

// SEO - tentar buscar ou usar defaults
let seoTitle = title + ' | Santos Cleaning Solutions';
let metaDescription = '';
try {
  const seoData = $('🔄 Parse SEO').all()[0].json;
  seoTitle = seoData?.seo?.title_tag || seoTitle;
  metaDescription = seoData?.seo?.meta_description || '';
} catch (e) {}

// META DESCRIPTION MELHORADA (150-160 chars, keyword, cidade, CTA)
if (!metaDescription || metaDescription.length < 100) {
  metaDescription = `Discover ${primaryKeyword} in ${targetCity}, GA. Professional cleaning services for homes and businesses. Contact Santos Cleaning today for a free quote!`;
}
// Garantir tamanho adequado
if (metaDescription.length > 160) {
  metaDescription = metaDescription.substring(0, 157) + '...';
}

// Datas
const now = new Date();
const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
const dateFormatted = `${monthNames[now.getMonth()]} ${now.getDate()}, ${now.getFullYear()}`;
const dateISO = now.toISOString().split('T')[0];

